import { AIProjectsClient } from "@azure/ai-projects";
import { DefaultAzureCredential } from "@azure/identity";

const credential = new DefaultAzureCredential();
const client = new AIProjectsClient(
    "https://your-project.openai.azure.com/",
    credential,
    { apiVersion: "2024-10-21" }
);

async function streamAgentResponse(threadId: string, message: string) {
    // Add message
    await client.getAgents().createOrGetAgentThread(
        "your-chatbot-agent-id",
        threadId,
        [{ role: "user", content: message }]
    );

    // Stream run
    const runStream = await client.getAgents().streamRun(
        "your-chatbot-agent-id",
        threadId,
        {
            model: "gpt-4o",
            tools: [{ type: "bing_search" }, { type: "file_search" }]
        }
    );

    for await (const event of runStream) {
        if (event.type === "text-delta") {
            process.stdout.write(event.delta);
        }
    }
}

async function monitorThreadTokens(client: AIProjectsClient, threadId: string) {
    const thread = await client.getAgents().retrieveThread(
        "your-chatbot-agent-id",
        threadId
    );

    const tokenUsage = await client.getAgents().listMessages(
        "your-chatbot-agent-id",
        threadId,
        { limit: 100 }
    );

    let totalTokens = 0;
    for (const msg of tokenUsage.data) {
        totalTokens += msg.usage?.total_tokens || 0;
    }

    if (totalTokens > 100000) { // 80% of 128k limit
        console.log("⚠️  Token limit approaching - summarizing thread");
        await summarizeThread(client, threadId);
    }

    return totalTokens;
}

