from vex_sdk import VexClient
from azure.ai.projects import AIProjectsClient

vex = VexClient(api_key="your-vex-api-key")

async def validated_agent_run(client: AIProjectsClient, agent_id: str, thread_id: str):
    run = await client.agents.create_run(agent_id, thread_id)

    # Poll run steps for tool calls
    while run.status != "completed":
        steps = await client.agents.list_run_steps(agent_id, thread_id, run.id)

        for step in steps.data:
            if step.type == "tool_calls":
                for tool_call in step.tool_calls:
                    # Validate tool output with Vex
                    result = await vex.validate_tool_output(
                        tool_output=tool_call.output,
                        policies=[
                            "no_pii",
                            "no_financial_data",
                            "content_freshness_7d"
                        ],
                        context={"agent": "chatbot", "thread": thread_id}
                    )

                    if not result.valid:
                        raise ValueError(f"Tool validation failed: {result.violations}")

        await asyncio.sleep(0.5)

    return run

import { VexClient } from "vex-sdk";

const vex = new VexClient({ apiKey: "your-vex-api-key" });

async function createVexProtectedAgentRun(
    azureClient: AIProjectsClient,
    agentId: string,
    threadId: string
) {
    const runId = await azureClient.getAgents().createRun(agentId, threadId);

    // Vex monitors token usage in real-time
    const tokenMonitor = await vex.createTokenMonitor({
        threadId,
        maxTokens: 110000,  // 85% of 128k
        agentId,
        onWarning: async (usage) => {
            console.log(`⚠️  ${usage.current}/${usage.max} tokens`);

            // Auto-summarize when approaching limit
            if (usage.percent > 0.8) {
                const summary = await vex.summarizeConversation(
                    threadId,
                    max_length=2000
                );

                await azureClient.getAgents().createMessage(
                    agentId,
                    threadId,
                    {
                        role: "system",
                        content: `Thread Summary: ${summary}. Continue conversation.`
                    }
                );
            }
        }
    });

    return runId;
}
